			}
			CheckUpdating();
			int num = FindExistingUpdate(entry);
			if (num >= 0)
			{
				contentsEdited_ = true;
				updates_[num] = null;
				updateCount_--;
				return;
			}
			throw new ZipException("Cannot find entry to delete");
		}

		private void WriteLEShort(int value)
		{
			baseStream_.WriteByte((byte)(value & 0xFF));
