		private void WriteLocalHeader(ZipEntry entry, EntryPatchData patchData)
		{
			CompressionMethod compressionMethod = entry.CompressionMethod;
			bool flag = true;
			bool flag2 = false;
			WriteLEInt(67324752);
			WriteLEShort(entry.Version);
			WriteLEShort(entry.Flags);
			WriteLEShort((byte)compressionMethod);
			WriteLEInt((int)entry.DosTime);
			if (flag)
			{
				WriteLEInt((int)entry.Crc);
				if (entry.LocalHeaderRequiresZip64)
				{
					WriteLEInt(-1);
					WriteLEInt(-1);
				}
				else
				{
					WriteLEInt((int)(entry.IsCrypted ? ((int)entry.CompressedSize + 12) : entry.CompressedSize));
					WriteLEInt((int)entry.Size);
				}
			}
			else
			{
				if (patchData != null)
				{
					patchData.CrcPatchOffset = stream_.Position;
				}
				WriteLEInt(0);
				if (patchData != null)
				{
					patchData.SizePatchOffset = stream_.Position;
				}
				if (entry.LocalHeaderRequiresZip64 && flag2)
				{
					WriteLEInt(-1);
					WriteLEInt(-1);
				}
				else
				{
					WriteLEInt(0);
					WriteLEInt(0);
				}
			}
			byte[] array = ZipStrings.ConvertToArray(entry.Flags, entry.Name);
			if (array.Length > 65535)
			{
				throw new ZipException("Entry name too long.");
			}
			ZipExtraData zipExtraData = new ZipExtraData(entry.ExtraData);
			if (entry.LocalHeaderRequiresZip64 && (flag || flag2))
			{
				zipExtraData.StartNewEntry();
				if (flag)
				{
					zipExtraData.AddLeLong(entry.Size);
					zipExtraData.AddLeLong(entry.CompressedSize);
				}
				else
				{
					zipExtraData.AddLeLong(-1L);
					zipExtraData.AddLeLong(-1L);
				}
				zipExtraData.AddNewEntry(1);
				if (!zipExtraData.Find(1))
				{
					throw new ZipException("Internal error cant find extra data");
				}
				if (patchData != null)
				{
					patchData.SizePatchOffset = zipExtraData.CurrentReadIndex;
				}
			}
			else
			{
				zipExtraData.Delete(1);
			}
			byte[] entryData = zipExtraData.GetEntryData();
			WriteLEShort(array.Length);
			WriteLEShort(entryData.Length);
			if (array.Length != 0)
			{
				stream_.Write(array, 0, array.Length);
			}
			if (entry.LocalHeaderRequiresZip64 && flag2)
			{
				patchData.SizePatchOffset += stream_.Position;
			}
			if (entryData.Length != 0)
			{
				stream_.Write(entryData, 0, entryData.Length);
			}
		}

		public long LocateBlockWithSignature(int signature, long endLocation, int minimumBlockSize, int maximumVariableData)
		{
			long num = endLocation - minimumBlockSize;
			if (num < 0)
			{
				return -1L;
			}
			long num2 = Math.Max(num - maximumVariableData, 0L);
			do
			{
				if (num < num2)
				{
					return -1L;
				}
				Seek(num--, SeekOrigin.Begin);
			}
			while (ReadLEInt() != signature);
			return Position;
		}

		public void WriteZip64EndOfCentralDirectory(long noOfEntries, long sizeEntries, long centralDirOffset)
		{
			long value = centralDirOffset + sizeEntries;
			WriteLEInt(101075792);
			WriteLELong(44L);
			WriteLEShort(51);
			WriteLEShort(45);
			WriteLEInt(0);
			WriteLEInt(0);
			WriteLELong(noOfEntries);
			WriteLELong(noOfEntries);
			WriteLELong(sizeEntries);
			WriteLELong(centralDirOffset);
			WriteLEInt(117853008);
			WriteLEInt(0);
			WriteLELong(value);
			WriteLEInt(1);
		}

		public void WriteEndOfCentralDirectory(long noOfEntries, long sizeEntries, long startOfCentralDirectory, byte[] comment)
		{
			if (noOfEntries >= 65535 || startOfCentralDirectory >= uint.MaxValue || sizeEntries >= uint.MaxValue)
			{
				WriteZip64EndOfCentralDirectory(noOfEntries, sizeEntries, startOfCentralDirectory);
			}
			WriteLEInt(101010256);
			WriteLEShort(0);
			WriteLEShort(0);
			if (noOfEntries >= 65535)
			{
				WriteLEUshort(ushort.MaxValue);
				WriteLEUshort(ushort.MaxValue);
			}
			else
			{
				WriteLEShort((short)noOfEntries);
				WriteLEShort((short)noOfEntries);
			}
			if (sizeEntries >= uint.MaxValue)
			{
				WriteLEUint(uint.MaxValue);
			}
			else
			{
				WriteLEInt((int)sizeEntries);
			}
			if (startOfCentralDirectory >= uint.MaxValue)
			{
				WriteLEUint(uint.MaxValue);
			}
			else
			{
				WriteLEInt((int)startOfCentralDirectory);
			}
			int num = ((comment != null) ? comment.Length : 0);
			if (num > 65535)
			{
				throw new ZipException($"Comment length({num}) is too long can only be 64K");
			}
			WriteLEShort(num);
			if (num > 0)
			{
				Write(comment, 0, comment.Length);
			}
		}

		public int ReadLEShort()
		{
			int num = stream_.ReadByte();
			if (num < 0)
			{
				throw new EndOfStreamException();
			}
			int num2 = stream_.ReadByte();
			if (num2 < 0)
			{
				throw new EndOfStreamException();
			}
			return num | (num2 << 8);
		}

		public int ReadLEInt()
		{
			return ReadLEShort() | (ReadLEShort() << 16);
		}

		public long ReadLELong()
		{
			return (uint)ReadLEInt() | ((long)ReadLEInt() << 32);
		}

		public void WriteLEShort(int value)
		{
			stream_.WriteByte((byte)(value & 0xFF));
			stream_.WriteByte((byte)((value >> 8) & 0xFF));
		}

		public void WriteLEUshort(ushort value)
		{
			stream_.WriteByte((byte)(value & 0xFF));
			stream_.WriteByte((byte)(value >> 8));
		}

		public void WriteLEInt(int value)
		{
			WriteLEShort(value);
			WriteLEShort(value >> 16);
		}

		public void WriteLEUint(uint value)
		{
			WriteLEUshort((ushort)(value & 0xFFFF));
			WriteLEUshort((ushort)(value >> 16));
		}

		public void WriteLELong(long value)
		{
			WriteLEInt((int)value);
			WriteLEInt((int)(value >> 32));
		}

		public void WriteLEUlong(ulong value)
		{
			WriteLEUint((uint)(value & 0xFFFFFFFFu));
			WriteLEUint((uint)(value >> 32));
		}

		public int WriteDataDescriptor(ZipEntry entry)
		{
			if (entry == null)
			{
				throw new ArgumentNullException("entry");
			}
			int num = 0;
			if ((entry.Flags & 8) != 0)
			{
				WriteLEInt(134695760);
				WriteLEInt((int)entry.Crc);
				num += 8;
				if (entry.LocalHeaderRequiresZip64)
				{
					WriteLELong(entry.CompressedSize);
					WriteLELong(entry.Size);
					num += 16;
				}
				else
				{
					WriteLEInt((int)entry.CompressedSize);
					WriteLEInt((int)entry.Size);
					num += 8;
				}
			}
			return num;
		}

		public void ReadDataDescriptor(bool zip64, DescriptorData data)
		{
			if (ReadLEInt() != 134695760)
			{
				throw new ZipException("Data descriptor signature not found");
			}
			data.Crc = ReadLEInt();
			if (zip64)
			{
				data.CompressedSize = ReadLELong();
				data.Size = ReadLELong();
			}
			else
			{
				data.CompressedSize = ReadLEInt();
				data.Size = ReadLEInt();
			}
		}
	}
	public class ZipInputStream : InflaterInputStream
	{
		private delegate int ReadDataHandler(byte[] b, int offset, int length);

		private ReadDataHandler internalReader;

		private Crc32 crc = new Crc32();

		private ZipEntry entry;

		private long size;

		private CompressionMethod method;

		private int flags;

		private string password;

		public string Password
		{
			get
			{
				return password;
			}
			set
			{
				password = value;
			}
		}

		public bool CanDecompressEntry
		{
			get
			{
				if (entry != null && IsEntryCompressionMethodSupported(entry) && entry.CanDecompress)
				{
					if (entry.HasFlag(GeneralBitFlags.Descriptor) && entry.CompressionMethod == CompressionMethod.Stored)
					{
						return entry.IsCrypted;
					}
					return true;
				}
				return false;
			}
		}

		public override int Available
		{
			get
			{
				if (entry == null)
				{
					return 0;
				}
				return 1;
			}
		}

		public override long Length
		{
			get
			{
				if (entry != null)
				{
					if (entry.Size >= 0)
					{
						return entry.Size;
					}
					throw new ZipException("Length not available for the current entry");
				}
				throw new InvalidOperationException("No current entry");
			}
		}

		public ZipInputStream(Stream baseInputStream)
			: base(baseInputStream, new Inflater(noHeader: true))
		{
			internalReader = ReadingNotAvailable;
		}

		public ZipInputStream(Stream baseInputStream, int bufferSize)
			: base(baseInputStream, new Inflater(noHeader: true), bufferSize)
		{
			internalReader = ReadingNotAvailable;
		}

		private static bool IsEntryCompressionMethodSupported(ZipEntry entry)
		{
			CompressionMethod compressionMethodForHeader = entry.CompressionMethodForHeader;
			if (compressionMethodForHeader != CompressionMethod.Deflated)
			{
				return compressionMethodForHeader == CompressionMethod.Stored;
			}
			return true;
		}

		public ZipEntry GetNextEntry()
		{
			if (crc == null)
			{
				throw new InvalidOperationException("Closed.");
			}
			if (entry != null)
			{
				CloseEntry();
			}
			int num = inputBuffer.ReadLeInt();
			switch (num)
			{
			case 33639248:
			case 84233040:
			case 101010256:
			case 101075792:
			case 117853008:
				Dispose();
				return null;
			case 134695760:
			case 808471376:
				num = inputBuffer.ReadLeInt();
				break;
			}
			if (num != 67324752)
			{
				throw new ZipException("Wrong Local header signature: 0x" + $"{num:X}");
			}
			short versionRequiredToExtract = (short)inputBuffer.ReadLeShort();
			flags = inputBuffer.ReadLeShort();
			method = (CompressionMethod)inputBuffer.ReadLeShort();
			uint num2 = (uint)inputBuffer.ReadLeInt();
			int num3 = inputBuffer.ReadLeInt();
			csize = inputBuffer.ReadLeInt();
			size = inputBuffer.ReadLeInt();
			int num4 = inputBuffer.ReadLeShort();
			int num5 = inputBuffer.ReadLeShort();
			bool flag = (flags & 1) == 1;
			byte[] array = new byte[num4];
			inputBuffer.ReadRawBuffer(array);
			string name = ZipStrings.ConvertToStringExt(flags, array);
			entry = new ZipEntry(name, versionRequiredToExtract, 51, method)
			{
				Flags = flags
			};
			if ((flags & 8) == 0)
			{
				entry.Crc = num3 & 0xFFFFFFFFu;
				entry.Size = size & 0xFFFFFFFFu;
				entry.CompressedSize = csize & 0xFFFFFFFFu;
				entry.CryptoCheckValue = (byte)((num3 >> 24) & 0xFF);
			}
			else
			{
				if (num3 != 0)
				{
