			{
				throw new InvalidOperationException("Closed");
			}
			if (entry == null)
			{
				return;
			}
			if (method == CompressionMethod.Deflated)
			{
				if ((flags & 8) != 0)
				{
					byte[] array = new byte[4096];
					while (Read(array, 0, array.Length) > 0)
