					}
					return;
				}
				csize -= inf.TotalIn;
				inputBuffer.Available += inf.RemainingInput;
			}
			if (inputBuffer.Available > csize && csize >= 0)
			{
				inputBuffer.Available = (int)(inputBuffer.Available - csize);
