				inputBuffer.ReadClearTextBuffer(array, 0, 12);
				if (array[11] != entry.CryptoCheckValue)
				{
					throw new ZipException("Invalid password");
				}
				if (csize >= 12)
				{
					csize -= 12L;
				}
				else if (!flag)
