		}

		public Inflater(bool noHeader)
		{
			this.noHeader = noHeader;
			if (!noHeader)
			{
				adler = new Adler32();
			}
			input = new StreamManipulator();
			outputWindow = new OutputWindow();
			mode = (noHeader ? 2 : 0);
		}

		public void Reset()
		{
			mode = (noHeader ? 2 : 0);
			totalIn = 0L;
			totalOut = 0L;
			input.Reset();
			outputWindow.Reset();
			dynHeader = null;
			litlenTree = null;
			distTree = null;
			isLastBlock = false;
			adler?.Reset();
		}

		private bool DecodeHeader()
		{
			int num = input.PeekBits(16);
			if (num < 0)
			{
				return false;
			}
			input.DropBits(16);
			num = ((num << 8) | (num >> 8)) & 0xFFFF;
			if (num % 31 != 0)
