			if ((num & 0x20) == 0)
			{
				mode = 2;
			}
			else
			{
				mode = 1;
				neededBits = 32;
			}
			return true;
		}

		private bool DecodeDict()
		{
			while (neededBits > 0)
			{
				int num = input.PeekBits(8);
				if (num < 0)
				{
					return false;
				}
				input.DropBits(8);
				readAdler = (readAdler << 8) | num;
				neededBits -= 8;
			}
			return false;
		}

		private bool DecodeHuffman()
