						repDist = CPDIST[symbol];
						neededBits = CPDEXT[symbol];
					}
					catch (Exception)
					{
						throw new SharpZipBaseException("Illegal rep dist code");
					}
					goto case 10;
				}
				case 10:
					if (neededBits > 0)
