				{
					Decode();
				}
				return 0;
			}
			int num = 0;
			do
			{
				if (mode == 11)
				{
					continue;
				}
				int num2 = outputWindow.CopyOutput(buffer, offset, count);
				if (num2 > 0)
				{
					adler?.Update(new ArraySegment<byte>(buffer, offset, num2));
					offset += num2;
					num += num2;
					totalOut += num2;
					count -= num2;
					if (count == 0)
					{
