				if (num <= 0)
				{
					break;
				}
				if (cryptoTransform_ != null)
				{
					EncryptBlock(buffer_, 0, num);
				}
				baseOutputStream_.Write(buffer_, 0, num);
			}
			if (!deflater_.IsNeedingInput)
