		}

		public override void Flush()
		{
			deflater_.Flush();
			Deflate(flushing: true);
			baseOutputStream_.Flush();
		}

		protected override void Dispose(bool disposing)
		{
			if (isClosed_)
			{
				return;
			}
			isClosed_ = true;
			try
			{
				Finish();
