	public class StreamManipulator
	{
		private byte[] window_;

		private int windowStart_;

		private int windowEnd_;

		private uint buffer_;

		private int bitsInBuffer_;

		public int AvailableBits => bitsInBuffer_;

		public int AvailableBytes => windowEnd_ - windowStart_ + (bitsInBuffer_ >> 3);

		public bool IsNeedingInput => windowStart_ == windowEnd_;

		public int PeekBits(int bitCount)
		{
			if (bitsInBuffer_ < bitCount)
			{
				if (windowStart_ == windowEnd_)
				{
					return -1;
				}
				buffer_ |= (uint)(((window_[windowStart_++] & 0xFF) | ((window_[windowStart_++] & 0xFF) << 8)) << bitsInBuffer_);
				bitsInBuffer_ += 16;
			}
			return (int)(buffer_ & ((1 << bitCount) - 1));
		}

		public bool TryGetBits(int bitCount, ref int output, int outputOffset = 0)
		{
			int num = PeekBits(bitCount);
			if (num < 0)
			{
				return false;
			}
			output = num + outputOffset;
			DropBits(bitCount);
			return true;
		}

		public bool TryGetBits(int bitCount, ref byte[] array, int index)
		{
			int num = PeekBits(bitCount);
			if (num < 0)
			{
				return false;
			}
			array[index] = (byte)num;
			DropBits(bitCount);
			return true;
		}

		public void DropBits(int bitCount)
		{
			buffer_ >>= bitCount;
			bitsInBuffer_ -= bitCount;
		}

		public int GetBits(int bitCount)
		{
			int num = PeekBits(bitCount);
			if (num >= 0)
			{
				DropBits(bitCount);
			}
			return num;
		}

		public void SkipToByteBoundary()
		{
			buffer_ >>= bitsInBuffer_ & 7;
			bitsInBuffer_ &= -8;
		}

		public int CopyBytes(byte[] output, int offset, int length)
		{
			if (length < 0)
			{
				throw new ArgumentOutOfRangeException("length");
			}
			if ((bitsInBuffer_ & 7) != 0)
			{
				throw new InvalidOperationException("Bit buffer is not byte aligned!");
			}
			int num = 0;
			while (bitsInBuffer_ > 0 && length > 0)
			{
				output[offset++] = (byte)buffer_;
				buffer_ >>= 8;
				bitsInBuffer_ -= 8;
				length--;
				num++;
			}
			if (length == 0)
			{
				return num;
			}
			int num2 = windowEnd_ - windowStart_;
			if (length > num2)
			{
				length = num2;
			}
			Array.Copy(window_, windowStart_, output, offset, length);
			windowStart_ += length;
			if (((windowStart_ - windowEnd_) & 1) != 0)
			{
				buffer_ = (uint)(window_[windowStart_++] & 0xFF);
				bitsInBuffer_ = 8;
			}
			return num + length;
		}

		public void Reset()
		{
			buffer_ = 0u;
			windowStart_ = (windowEnd_ = (bitsInBuffer_ = 0));
		}

		public void SetInput(byte[] buffer, int offset, int count)
		{
			if (buffer == null)
			{
				throw new ArgumentNullException("buffer");
			}
			if (offset < 0)
			{
				throw new ArgumentOutOfRangeException("offset", "Cannot be negative");
			}
			if (count < 0)
			{
				throw new ArgumentOutOfRangeException("count", "Cannot be negative");
			}
			if (windowStart_ < windowEnd_)
			{
				throw new InvalidOperationException("Old input was not completely processed");
			}
			int num = offset + count;
			if (offset > num || num > buffer.Length)
			{
				throw new ArgumentOutOfRangeException("count");
			}
			if ((count & 1) != 0)
			{
				buffer_ |= (uint)((buffer[offset++] & 0xFF) << bitsInBuffer_);
				bitsInBuffer_ += 8;
			}
			window_ = buffer;
			windowStart_ = offset;
			windowEnd_ = num;
		}
	}
