			string fullPath = Path.GetFullPath(destinationDirectory);
			while (true)
			{
				TarEntry nextEntry = tarIn.GetNextEntry();
				if (nextEntry != null)
				{
					if (nextEntry.TarHeader.TypeFlag != 49 && nextEntry.TarHeader.TypeFlag != 50)
					{
						ExtractEntry(fullPath, nextEntry, allowParentTraversal);
					}
					continue;
				}
				break;
			}
		}

		private void ExtractEntry(string destDir, TarEntry entry, bool allowParentTraversal)
		{
			OnProgressMessageEvent(entry, null);
			string text = entry.Name;
			if (Path.IsPathRooted(text))
			{
				text = text.Substring(Path.GetPathRoot(text).Length);
			}
			text = text.Replace('/', Path.DirectorySeparatorChar);
			string text2 = Path.Combine(destDir, text);
			if (!allowParentTraversal && !Path.GetFullPath(text2).StartsWith(destDir, StringComparison.InvariantCultureIgnoreCase))
			{
				throw new InvalidNameException("Parent traversal in paths is not allowed");
			}
			if (entry.IsDirectory)
			{
				EnsureDirectoryExists(text2);
				return;
			}
			EnsureDirectoryExists(Path.GetDirectoryName(text2));
			bool flag = true;
			FileInfo fileInfo = new FileInfo(text2);
			if (fileInfo.Exists)
			{
				if (keepOldFiles)
				{
					OnProgressMessageEvent(entry, "Destination file already exists");
					flag = false;
				}
				else if ((fileInfo.Attributes & FileAttributes.ReadOnly) != 0)
				{
					OnProgressMessageEvent(entry, "Destination file already exists, and is read-only");
					flag = false;
				}
			}
			if (!flag)
			{
				return;
			}
			using FileStream outputStream = File.Create(text2);
			if (asciiTranslate)
			{
				ExtractAndTranslateEntry(text2, outputStream);
			}
			else
			{
				tarIn.CopyEntryContents(outputStream);
			}
		}

		private void ExtractAndTranslateEntry(string destFile, Stream outputStream)
		{
			if (!IsBinary(destFile))
			{
				using (StreamWriter streamWriter = new StreamWriter(outputStream, new UTF8Encoding(encoderShouldEmitUTF8Identifier: false), 1024, leaveOpen: true))
				{
					byte[] array = new byte[32768];
					while (true)
					{
						int num = tarIn.Read(array, 0, array.Length);
						if (num <= 0)
						{
							break;
						}
						int num2 = 0;
						for (int i = 0; i < num; i++)
						{
							if (array[i] == 10)
							{
								string value = Encoding.ASCII.GetString(array, num2, i - num2);
								streamWriter.WriteLine(value);
								num2 = i + 1;
							}
						}
					}
					return;
				}
			}
			tarIn.CopyEntryContents(outputStream);
		}

		public void WriteEntry(TarEntry sourceEntry, bool recurse)
		{
			if (sourceEntry == null)
			{
				throw new ArgumentNullException("sourceEntry");
			}
			if (isDisposed)
			{
				throw new ObjectDisposedException("TarArchive");
			}
			try
			{
				if (recurse)
				{
					TarHeader.SetValueDefaults(sourceEntry.UserId, sourceEntry.UserName, sourceEntry.GroupId, sourceEntry.GroupName);
				}
				WriteEntryCore(sourceEntry, recurse);
			}
			finally
			{
				if (recurse)
				{
					TarHeader.RestoreSetValues();
				}
			}
		}

		private void WriteEntryCore(TarEntry sourceEntry, bool recurse)
		{
			string text = null;
			string text2 = sourceEntry.File;
			TarEntry tarEntry = (TarEntry)sourceEntry.Clone();
			if (applyUserInfoOverrides)
			{
				tarEntry.GroupId = groupId;
				tarEntry.GroupName = groupName;
				tarEntry.UserId = userId;
				tarEntry.UserName = userName;
			}
			OnProgressMessageEvent(tarEntry, null);
			if (asciiTranslate && !tarEntry.IsDirectory && !IsBinary(text2))
			{
				text = PathUtils.GetTempFileName();
				using (StreamReader streamReader = File.OpenText(text2))
				{
					using Stream stream = File.Create(text);
					while (true)
					{
						string text3 = streamReader.ReadLine();
						if (text3 == null)
						{
							break;
						}
						byte[] bytes = Encoding.ASCII.GetBytes(text3);
						stream.Write(bytes, 0, bytes.Length);
						stream.WriteByte(10);
					}
					stream.Flush();
				}
				tarEntry.Size = new FileInfo(text).Length;
				text2 = text;
			}
			string text4 = null;
			if (!string.IsNullOrEmpty(rootPath) && tarEntry.Name.StartsWith(rootPath, StringComparison.OrdinalIgnoreCase))
			{
				text4 = tarEntry.Name.Substring(rootPath.Length + 1);
			}
			if (pathPrefix != null)
			{
				text4 = ((text4 == null) ? (pathPrefix + "/" + tarEntry.Name) : (pathPrefix + "/" + text4));
			}
			if (text4 != null)
			{
				tarEntry.Name = text4;
			}
			tarOut.PutNextEntry(tarEntry);
			if (tarEntry.IsDirectory)
			{
				if (recurse)
				{
					TarEntry[] directoryEntries = tarEntry.GetDirectoryEntries();
					for (int i = 0; i < directoryEntries.Length; i++)
					{
						WriteEntryCore(directoryEntries[i], recurse);
					}
				}
				return;
			}
			using (Stream stream2 = File.OpenRead(text2))
			{
				byte[] array = new byte[32768];
				while (true)
				{
					int num = stream2.Read(array, 0, array.Length);
					if (num <= 0)
					{
						break;
					}
					tarOut.Write(array, 0, num);
				}
			}
			if (!string.IsNullOrEmpty(text))
			{
				File.Delete(text);
			}
			tarOut.CloseEntry();
		}

		public void Dispose()
