		protected virtual void Dispose(bool disposing)
		{
			if (isDisposed)
			{
				return;
			}
			isDisposed = true;
			if (disposing)
			{
				if (tarOut != null)
				{
					tarOut.Flush();
					tarOut.Dispose();
				}
				if (tarIn != null)
				{
					tarIn.Dispose();
				}
			}
		}

		public virtual void Close()
		{
