		public void ParseBuffer(byte[] header, Encoding nameEncoding)
		{
			if (header == null)
			{
				throw new ArgumentNullException("header");
			}
			int num = 0;
			name = ParseName(header, num, 100, nameEncoding).ToString();
			num += 100;
			mode = (int)ParseOctal(header, num, 8);
			num += 8;
			UserId = (int)ParseOctal(header, num, 8);
			num += 8;
			GroupId = (int)ParseOctal(header, num, 8);
			num += 8;
			Size = ParseBinaryOrOctal(header, num, 12);
			num += 12;
			ModTime = GetDateTimeFromCTime(ParseOctal(header, num, 12));
			num += 12;
			checksum = (int)ParseOctal(header, num, 8);
			num += 8;
			TypeFlag = header[num++];
			LinkName = ParseName(header, num, 100, nameEncoding).ToString();
			num += 100;
			Magic = ParseName(header, num, 6, nameEncoding).ToString();
			num += 6;
			if (Magic == "ustar")
			{
				Version = ParseName(header, num, 2, nameEncoding).ToString();
				num += 2;
				UserName = ParseName(header, num, 32, nameEncoding).ToString();
				num += 32;
				GroupName = ParseName(header, num, 32, nameEncoding).ToString();
				num += 32;
				DevMajor = (int)ParseOctal(header, num, 8);
				num += 8;
				DevMinor = (int)ParseOctal(header, num, 8);
				num += 8;
				string text = ParseName(header, num, 155, nameEncoding).ToString();
				if (!string.IsNullOrEmpty(text))
				{
					Name = text + "/" + Name;
				}
			}
			isChecksumValid = Checksum == MakeCheckSum(header);
		}

