		public void WriteHeader(byte[] outBuffer, Encoding nameEncoding)
		{
			if (outBuffer == null)
			{
				throw new ArgumentNullException("outBuffer");
			}
			int offset = 0;
			offset = GetNameBytes(Name, outBuffer, offset, 100, nameEncoding);
