				(byte)((array[0] >> 24) & 0xFF),
				(byte)(array[1] & 0xFF),
				(byte)((array[1] >> 8) & 0xFF),
				(byte)((array[1] >> 16) & 0xFF),
				(byte)((array[1] >> 24) & 0xFF),
				(byte)(array[2] & 0xFF),
				(byte)((array[2] >> 8) & 0xFF),
				(byte)((array[2] >> 16) & 0xFF),
