	[Serializable]
	public class ModIndex
	{
		[Serializable]
		internal class IndexEntry
		{
			public const long ID_NONE = -1L;

			public long DownloadedModfileId = -1L;

			public long InstalledModfileId = -1L;

			public long InstallationSize;

			public List<long> Subscribers = new List<long>();

			public DateTime ExpiresAfter = DateTime.UnixEpoch;

			public ModFileState FileState;
		}

		[JsonProperty]
		internal Dictionary<long, IndexEntry> Index = new Dictionary<long, IndexEntry>();

		[JsonProperty]
		internal Dictionary<long, ModObject> ModObjectCache = new Dictionary<long, ModObject>();

		[JsonIgnore]
		public bool IsDirty { get; internal set; }

		public ModIndex()
		{
			Mod.AddChangeListener(ModChangeType.ModObject, OnModObjectUpdate);
		}

		internal static async Task<(Error error, ModIndex result)> CreateIndexFromScan()
		{
			ModIndex output = new ModIndex();
			(Error, UserSaveObject[]) tuple = await ModioClient.DataStorage.ReadAllSavedUserData();
			if (!tuple.Item1)
			{
				UserSaveObject[] item = tuple.Item2;
				foreach (UserSaveObject userSaveObject in item)
				{
					foreach (long subscribedMod in userSaveObject.SubscribedMods)
					{
						if (output.Index.TryGetValue(subscribedMod, out var value) && !value.Subscribers.Contains(userSaveObject.UserId))
						{
							value.Subscribers.Add(userSaveObject.UserId);
							continue;
						}
						output.Index[subscribedMod] = new IndexEntry
						{
							Subscribers = new List<long> { userSaveObject.UserId }
						};
					}
				}
			}
			(Error, List<(long, long)>) tuple2 = await ModioClient.DataStorage.ScanForModfiles();
			if (!tuple2.Item1)
			{
				foreach (var (key, downloadedModfileId) in tuple2.Item2)
				{
					if (output.Index.TryGetValue(key, out var value2))
					{
						value2.DownloadedModfileId = downloadedModfileId;
						continue;
					}
					output.Index[key] = new IndexEntry
					{
						DownloadedModfileId = downloadedModfileId,
						FileState = ModFileState.Downloaded
					};
				}
			}
			(Error, List<(long, long)>) tuple4 = await ModioClient.DataStorage.ScanForInstalledMods();
			if (!tuple4.Item1)
			{
				foreach (var (key2, installedModfileId) in tuple4.Item2)
				{
					if (output.Index.TryGetValue(key2, out var value3))
					{
						value3.InstalledModfileId = installedModfileId;
						continue;
					}
					output.Index[key2] = new IndexEntry
					{
						InstalledModfileId = installedModfileId,
						FileState = ModFileState.Installed
					};
				}
			}
			(Error, ICollection<Mod>) obj = await Mod.GetMods(output.Index.Keys, forceRefresh: false, output);
			IEnumerable<Mod> item2 = obj.Item2;
			Error item3 = obj.Item1;
			IEnumerable<Mod> enumerable = item2;
			if (!item3)
			{
				foreach (Mod item4 in enumerable)
				{
					output.ModObjectCache[item4.Id] = item4.LastModObject;
				}
			}
			return (error: Error.None, result: output);
		}

		internal async Task<bool> UpdateIndexWithMissingEntriesFromScan()
		{
			(Error, List<(long, long)>) tuple = await ModioClient.DataStorage.ScanForInstalledMods();
			List<long> list = null;
			if (!tuple.Item1)
			{
				foreach (var (num, installedModfileId) in tuple.Item2)
				{
					if (Index.TryGetValue(num, out var value))
					{
						if (value.InstalledModfileId == 0L)
						{
							value.InstalledModfileId = installedModfileId;
							value.FileState = ModFileState.Installed;
							IsDirty = true;
						}
						continue;
					}
					Index[num] = new IndexEntry
					{
						InstalledModfileId = installedModfileId,
						FileState = ModFileState.Installed
					};
					if (list == null)
					{
						list = new List<long>();
					}
					list.Add(num);
				}
			}
			if (list == null)
			{
				return false;
			}
			(Error, ICollection<Mod>) obj = await Mod.GetMods(list);
			IEnumerable<Mod> item = obj.Item2;
			Error item2 = obj.Item1;
			IEnumerable<Mod> enumerable = item;
			if (!item2)
			{
				foreach (Mod item3 in enumerable)
				{
					ModObjectCache[item3.Id] = item3.LastModObject;
				}
			}
			IsDirty = true;
			return true;
		}

		internal async Task<(bool modIsInstalled, long installedModFileId)> UpdateIndexForMod(Mod mod)
		{
			(Error, bool, long) tuple = await ModioClient.DataStorage.ScanForInstalledMod(mod);
			if ((bool)tuple.Item1 || !tuple.Item2)
			{
				return (modIsInstalled: false, installedModFileId: -1L);
			}
			if (Index.TryGetValue(mod.Id, out var value))
			{
				value.InstalledModfileId = tuple.Item3;
				value.FileState = ((mod.File.Id != tuple.Item3) ? ModFileState.Queued : ModFileState.Installed);
				IsDirty = true;
			}
			else
			{
				Index[mod.Id] = new IndexEntry
				{
					InstalledModfileId = tuple.Item3,
					FileState = ((mod.File.Id != tuple.Item3) ? ModFileState.Queued : ModFileState.Installed)
				};
			}
			ModObjectCache[mod.Id] = mod.LastModObject;
			IsDirty = true;
			return (modIsInstalled: true, installedModFileId: tuple.Item3);
		}

		internal IndexEntry GetEntry(Mod mod)
		{
			if (Index.TryGetValue(mod.Id, out var value))
			{
				return value;
			}
			value = new IndexEntry();
			Index[mod.Id] = value;
			ModObjectCache[mod.Id] = mod.LastModObject;
			mod.Logo?.CacheLowestResolutionOnDisk(shouldCache: true);
			return value;
		}

		internal bool TryGetEntry(ModId modId, out IndexEntry entry)
		{
			return Index.TryGetValue(modId, out entry);
		}

		internal void RemoveEntry(Mod mod)
		{
			Index.Remove(mod.Id);
			ModObjectCache.Remove(mod.Id);
			mod.Logo?.CacheLowestResolutionOnDisk(shouldCache: false);
		}

		internal void Shutdown()
		{
			Mod.RemoveChangeListener(ModChangeType.ModObject, OnModObjectUpdate);
		}

		private void OnModObjectUpdate(Mod mod, ModChangeType changeType)
		{
			if (TryGetEntry(mod.Id, out var _))
			{
				ModObjectCache[mod.Id] = mod.LastModObject;
				mod.Logo?.CacheLowestResolutionOnDisk(shouldCache: true);
			}
		}

		internal async Task RefreshIndexModObjects(bool installedOnly = true)
		{
			List<long> list = new List<long>();
			if (installedOnly)
			{
				foreach (KeyValuePair<long, IndexEntry> item3 in Index)
				{
					if (item3.Value.InstalledModfileId > 0)
					{
						list.Add(item3.Key);
					}
				}
			}
			else
			{
				list.AddRange(Index.Keys);
			}
			(Error, ICollection<Mod>) obj = await Mod.GetMods(list, forceRefresh: true);
			IEnumerable<Mod> item = obj.Item2;
			Error item2 = obj.Item1;
			IEnumerable<Mod> enumerable = item;
			if ((bool)item2)
			{
				return;
			}
			foreach (Mod item4 in enumerable)
			{
				ModObjectCache[item4.Id] = item4.LastModObject;
			}
		}
	}
	public static class ModInstallationManagement
	{
		public delegate void InstallationManagementEventDelegate(Mod mod, Modfile modfile, OperationType jobType, OperationPhase jobPhase);

		private abstract class Job
		{
			private readonly CancellationTokenSource _cancellationTokenSource;

			public Func<Task<Error>> Operation;

			public readonly OperationType Type;

			private Mod _mod;

			protected readonly CancellationToken CancellationToken;

			protected OperationPhase Phase;

			public Mod Mod
			{
				get
				{
					return _mod;
				}
				private set
				{
					_mod = value;
				}
			}

			protected Job(Mod mod, OperationType type)
			{
				Type = type;
				Mod = mod;
				_cancellationTokenSource = new CancellationTokenSource();
				CancellationToken = _cancellationTokenSource.Token;
			}

			public abstract Task<Error> Run();

			protected void PostEvent(OperationPhase jobPhase, ModFileState modState, Error errorCause = null)
			{
				if (Mod.File.State != modState)
				{
					Mod.File.State = modState;
					Mod.File.FileStateErrorCause = errorCause ?? Error.None;
					Mod.InvokeModUpdated(ModChangeType.FileState);
				}
				Phase = jobPhase;
				ModInstallationManagement.ManagementEvents?.Invoke(Mod, Mod.File, Type, jobPhase);
			}

			internal void Cancel()
			{
				_cancellationTokenSource.Cancel();
			}

			internal abstract void GetPendingSpaceChange(ref long spaceRequired, ref long tempSpaceRequired);

			protected internal void ClearMod()
			{
				Mod = null;
			}
		}

		private class DownloadJob : Job
		{
			public DownloadJob(Mod mod)
				: base(mod, OperationType.Download)
			{
			}

			public override async Task<Error> Run()
			{
				PostEvent(OperationPhase.Checking, ModFileState.Downloading);
				Error error;
				if (base.Mod.File.Download.ExpiresAfter < DateTime.Now.ToUniversalTime())
				{
					ModioLog.Verbose?.Log("Cached Modfile download for Mod " + base.Mod.Name + " has expired, getting new download");
					ModfileObject? modfileObject;
					(error, modfileObject) = await ModioAPI.Files.GetModfile(base.Mod.Id, base.Mod.File.Id);
					if ((bool)error)
					{
						PostEvent(OperationPhase.Failed, ModFileState.FileOperationFailed, error);
						return error;
					}
					if (!modfileObject.HasValue)
					{
						return new Error(ErrorCode.NO_DATA_AVAILABLE);
					}
					ModfileObject value = modfileObject.Value;
					base.Mod.UpdateModfile(new Modfile(value));
				}
				if (ModioClient.DataStorage.DoesModfileExist(base.Mod.Id, base.Mod.File.Id))
				{
					PostEvent(OperationPhase.Completed, base.Mod.File.State);
					return Error.None;
				}
				string downloadBinaryUrl = base.Mod.File.Download.BinaryUrl;
				long modfileId = base.Mod.File.Id;
				string filehashMd5 = base.Mod.File.Md5Hash;
				if (!(await ModioClient.DataStorage.IsThereAvailableFreeSpaceFor(base.Mod.File.ArchiveFileSize, base.Mod.File.FileSize)))
				{
					error = new Error(ErrorCode.INSUFFICIENT_SPACE);
					PostEvent(OperationPhase.Failed, ModFileState.FileOperationFailed, error);
					return error;
				}
				PostEvent(OperationPhase.Started, ModFileState.Downloading);
				Stream stream;
				(error, stream) = await ModioClient.Api.DownloadFile(downloadBinaryUrl, CancellationToken);
				if ((bool)error)
				{
					PostEvent(OperationPhase.Failed, ModFileState.FileOperationFailed, error);
					return error;
				}
				Task<Error> task = ModioClient.DataStorage.DownloadModFileFromStream(base.Mod.Id, modfileId, stream, filehashMd5, CancellationToken);
				if (CancellationToken.IsCancellationRequested)
				{
					await stream.DisposeAsync();
					PostEvent(OperationPhase.Cancelled, ModFileState.None);
					return new Error(ErrorCode.OPERATION_CANCELLED);
				}
				error = await task;
				if ((bool)error)
				{
					PostEvent(OperationPhase.Failed, ModFileState.FileOperationFailed, error);
					return error;
				}
				_index.GetEntry(base.Mod).FileState = ModFileState.Downloaded;
				_index.GetEntry(base.Mod).DownloadedModfileId = modfileId;
				await SaveIndex();
				PostEvent(OperationPhase.Completed, ModFileState.Downloaded);
				return error;
			}

			internal override void GetPendingSpaceChange(ref long spaceRequired, ref long tempSpaceRequired)
			{
				switch (Phase)
				{
				case OperationPhase.Checking:
					tempSpaceRequired += base.Mod.File.ArchiveFileSize;
					break;
				case OperationPhase.Started:
					tempSpaceRequired += (long)((float)base.Mod.File.ArchiveFileSize * (1f - base.Mod.File.FileStateProgress));
					break;
				}
			}
		}

		private class InstallJob : Job
		{
			private readonly bool _isUpdateJob;

			public InstallJob(Mod mod, bool isUpdateJob)
				: base(mod, (!isUpdateJob) ? OperationType.Install : OperationType.Update)
			{
				_isUpdateJob = isUpdateJob;
			}

			public override async Task<Error> Run()
			{
				ModFileState progressFileState = (_isUpdateJob ? ModFileState.Updating : ModFileState.Installing);
				PostEvent(OperationPhase.Checking, progressFileState);
				base.Mod.File.FileStateProgress = 0f;
				base.Mod.File.DownloadingBytesPerSecond = 0L;
				base.Mod.InvokeModUpdated(ModChangeType.DownloadProgress);
				if (ModioClient.DataStorage.DoesInstallExist(base.Mod.Id, base.Mod.File.Id))
				{
					_index.GetEntry(base.Mod).FileState = ModFileState.Installed;
					_index.GetEntry(base.Mod).InstalledModfileId = base.Mod.File.Id;
					await SaveIndex();
					PostEvent(OperationPhase.Completed, ModFileState.Installed);
					return Error.None;
				}
				if (!ModioClient.DataStorage.DoesModfileExist(base.Mod.Id, base.Mod.File.Id))
				{
					_operationQueue.Enqueue(new DownloadJob(base.Mod));
					_operationQueue.Enqueue(new InstallJob(base.Mod, _isUpdateJob));
					ModioLog.Error?.Log($"Unable to install mod {base.Mod.Id}_{base.Mod.File.Id} as Modfile could not be found!");
					PostEvent(OperationPhase.Failed, ModFileState.Queued);
					return new Error(ErrorCode.FILE_NOT_FOUND);
				}
				long num = base.Mod.File.FileSize;
				if (_isUpdateJob)
				{
					long installationSize = _index.GetEntry(base.Mod).InstallationSize;
					num -= installationSize;
				}
				bool flag = num > 0;
				if (flag)
				{
					flag = await ModioClient.DataStorage.IsThereAvailableFreeSpaceForModInstall(num);
				}
				Error error;
				if (!flag)
				{
					error = new Error(ErrorCode.INSUFFICIENT_SPACE);
					PostEvent(OperationPhase.Failed, ModFileState.FileOperationFailed, error);
					return error;
				}
				PostEvent(OperationPhase.Started, progressFileState);
				base.Mod.File.State = progressFileState;
				base.Mod.InvokeModUpdated(ModChangeType.FileState);
				if (_isUpdateJob)
				{
					error = await ModioClient.DataStorage.DeleteInstalledMod(base.Mod, _index.GetEntry(base.Mod).InstalledModfileId);
					if ((bool)error)
					{
						PostEvent(OperationPhase.Failed, ModFileState.FileOperationFailed, error);
						return error;
					}
				}
				error = await ModioClient.DataStorage.InstallMod(base.Mod, base.Mod.File.Id, CancellationToken);
				if (error.Code == ErrorCode.OPERATION_CANCELLED)
				{
					PostEvent(OperationPhase.Cancelled, ModFileState.None);
					return new Error(ErrorCode.OPERATION_CANCELLED);
				}
				if ((bool)error)
				{
					PostEvent(OperationPhase.Failed, ModFileState.FileOperationFailed, error);
					return error;
				}
				base.Mod.File.InstallLocation = ModioClient.DataStorage.GetInstallPath(base.Mod.Id, base.Mod.File.Id);
				_index.GetEntry(base.Mod).FileState = ModFileState.Installed;
				_index.GetEntry(base.Mod).InstalledModfileId = base.Mod.File.Id;
				await SaveIndex();
				PostEvent(OperationPhase.Completed, ModFileState.Installed);
				return Error.None;
			}

			internal override void GetPendingSpaceChange(ref long spaceRequired, ref long tempSpaceRequired)
			{
				tempSpaceRequired -= base.Mod.File.ArchiveFileSize;
				switch (Phase)
				{
				case OperationPhase.Checking:
					spaceRequired += base.Mod.File.FileSize;
					if (_isUpdateJob)
					{
						spaceRequired -= _index.GetEntry(base.Mod).InstallationSize;
					}
					break;
				case OperationPhase.Started:
					spaceRequired += (long)((double)base.Mod.File.FileSize * (1.0 - (double)base.Mod.File.FileStateProgress));
					if (_isUpdateJob && base.Mod.File.FileStateProgress == 0f)
					{
						spaceRequired -= _index.GetEntry(base.Mod).InstallationSize;
					}
					break;
				}
			}
		}

		private class DownloadAndExtractJob : Job
		{
			private bool IsUpdateJob => Type == OperationType.Update;

			public DownloadAndExtractJob(Mod mod, bool isUpdateJob)
				: base(mod, isUpdateJob ? OperationType.Update : OperationType.Download)
