				{
					PostEvent(OperationPhase.Failed, ModFileState.FileOperationFailed, error3);
					return error3;
				}
				PostEvent(OperationPhase.Completed, ModFileState.Downloaded);
				PostEvent(OperationPhase.Started, ModFileState.Installing);
