namespace Modio.Metrics
{
	public class MetricsManager
	{
		private const int HEARTBEAT_INTERVAL = 150;

		private readonly Dictionary<string, MetricsSession> _sessions = new Dictionary<string, MetricsSession>();

		private readonly MetricsSettings _settings;

		private string Secret
		{
			get
			{
				if (_settings != null)
				{
					return _settings.Secret;
				}
				return string.Empty;
			}
		}

		public MetricsManager()
		{
			ModioSettings modioSettings = ModioServices.Resolve<ModioSettings>();
			_settings = modioSettings.GetPlatformSettings<MetricsSettings>();
			if (string.IsNullOrEmpty(Secret))
			{
				ModioLog.Error?.Log("Metrics Secret has not been set.");
			}
		}

		public async Task<(string, Error)> StartSession()
		{
			string guid = Guid.NewGuid().ToString();
			return (guid, await StartSession(guid));
		}

		public async Task<Error> StartSession(string id)
		{
			return await StartSession(id, (from mod in User.Current.ModRepository.GetSubscribed()
				where mod.IsSubscribed && mod.IsEnabled
				select mod).Select((Func<Mod, long>)((Mod mod) => mod.Id)).ToArray());
		}

		public async Task<(string, Error)> StartSession(long[] mods)
		{
			string guid = Guid.NewGuid().ToString();
			return (guid, await StartSession(guid, mods));
		}

		public async Task<Error> StartSession(string id, long[] mods)
		{
			if (string.IsNullOrEmpty(Secret))
			{
				return new Error(ErrorCode.INVALID_METRICS_SECRET);
			}
			if (_sessions.ContainsKey(id))
			{
				ModioLog.Warning?.Log("Metric session '" + id + "' already active in session cache\nPlease start a session with a different ID");
				return Error.None;
			}
			MetricsSession session = new MetricsSession(id, mods);
			Error item = (await ModioAPI.Metrics.MetricsSessionStart(session.ToRequest(includeIds: true, Secret))).Item1;
			if ((bool)item)
			{
				ModioLog.Warning?.Log($"Metrics failed with: {item}");
				return item;
			}
			session.Active = true;
			_sessions.Add(session.SessionId, session);
			session.HeartbeatCancellationToken = new CancellationTokenSource();
			Heartbeat(session.SessionId).ForgetTaskSafely();
			return Error.None;
		}

		private async Task Heartbeat(string id)
		{
			if (string.IsNullOrEmpty(Secret) || !_sessions.TryGetValue(id, out var session))
			{
				return;
			}
			CancellationToken cancellationToken = session.HeartbeatCancellationToken.Token;
			try
			{
				while (!cancellationToken.IsCancellationRequested)
				{
					session.SessionOrderId++;
					Error item = (await ModioAPI.Metrics.MetricsSessionHeartbeat(session.ToRequest(includeIds: false, Secret))).Item1;
					if ((bool)item)
					{
						ModioLog.Warning?.Log($"Metrics failed with: {item}");
					}
					try
					{
						await Task.Delay(TimeSpan.FromSeconds(150.0), cancellationToken);
					}
					catch (TaskCanceledException)
					{
						break;
					}
				}
			}
			finally
			{
				session.HeartbeatCompletionSource.SetResult(result: true);
			}
		}

		public async Task<Error> EndSession(string id)
		{
			if (string.IsNullOrEmpty(Secret))
			{
				return new Error(ErrorCode.INVALID_METRICS_SECRET);
			}
			if (!_sessions.TryGetValue(id, out var session))
			{
				ModioLog.Warning?.Log("Metric session '" + id + "' not in session cache\nPlease make sure to start a session.");
				return Error.None;
			}
			if (!session.HeartbeatCancellationToken.Token.IsCancellationRequested)
			{
				session.HeartbeatCancellationToken.Cancel();
			}
			await session.HeartbeatCompletionSource.Task;
			Error item = (await ModioAPI.Metrics.MetricsSessionEnd(session.ToRequest(includeIds: false, Secret))).Item1;
			session.Active = false;
			if ((bool)item)
			{
				return Error.None;
			}
			ModioLog.Warning?.Log($"Metrics failed with: {item}");
			return item;
		}

		public void EndAllSessions()
		{
			foreach (MetricsSession item in _sessions.Values.Where((MetricsSession session) => session.Active))
			{
				EndSession(item.SessionId).ForgetTaskSafely();
			}
		}
	}
	public class MetricsSession
	{
		private readonly long[] _ids;

		internal readonly string SessionId;

		internal long SessionOrderId;

		internal bool Active;

		public CancellationTokenSource HeartbeatCancellationToken;

		public TaskCompletionSource<bool> HeartbeatCompletionSource;

		public MetricsSession(string id, long[] mods)
		{
			SessionId = id;
			_ids = mods;
			SessionOrderId = 2L;
		}

		private string GetSessionHash(bool includeIds, string sessionTs, string nonce, string secret)
		{
			string text = null;
			if (includeIds)
			{
				text = string.Join(",", _ids);
			}
			text = text + sessionTs + SessionId + nonce;
			byte[] bytes = Encoding.UTF8.GetBytes(secret);
			byte[] bytes2 = Encoding.UTF8.GetBytes(text);
			using HMACSHA256 hMACSHA = new HMACSHA256(bytes);
			return BitConverter.ToString(hMACSHA.ComputeHash(bytes2)).Replace("-", "").ToLower();
		}

		internal MetricsSessionRequest ToRequest(bool includeIds, string secret)
		{
			string text = Guid.NewGuid().ToString();
			long sessionTs = DateTimeOffset.UtcNow.ToUnixTimeMilliseconds();
			string sessionHash = GetSessionHash(includeIds, sessionTs.ToString(), text, secret);
			return new MetricsSessionRequest(SessionId, sessionTs, sessionHash, text, SessionOrderId, includeIds ? _ids : null);
		}
	}
	public class MetricsSettings : IModioServiceSettings
	{
		public string Secret;
	}
}
namespace Modio.Images
{
	public abstract class BaseImageCache
	{
		protected static readonly List<BaseImageCache> ImageCacheInstances = new List<BaseImageCache>();

		protected static readonly HashSet<ImageReference> PendingDiskSaves = new HashSet<ImageReference>();

		public static void CacheToDisk(ImageReference image, bool shouldCache)
		{
			if (!shouldCache)
			{
				ModioClient.DataStorage.DeleteCachedImage(new Uri(image.Url));
				PendingDiskSaves.Remove(image);
				return;
			}
			bool flag = false;
			foreach (BaseImageCache imageCacheInstance in ImageCacheInstances)
			{
				flag |= imageCacheInstance.CacheToDiskInternal(image);
			}
			if (!flag)
			{
				PendingDiskSaves.Add(image);
			}
		}

		protected abstract bool CacheToDiskInternal(ImageReference imageReference);
	}
	public abstract class BaseImageCache<T> : BaseImageCache where T : class
	{
		private readonly Dictionary<ImageReference, (Error, T)> _cache = new Dictionary<ImageReference, (Error, T)>();

		private readonly Dictionary<ImageReference, Task<(Error, T)>> _ongoingDownloads = new Dictionary<ImageReference, Task<(Error, T)>>();

		protected BaseImageCache()
		{
			BaseImageCache.ImageCacheInstances.Add(this);
		}

		public T GetCachedImage(ImageReference uri)
		{
			_cache.TryGetValue(uri, out var value);
			return value.Item2;
		}

		public Task<(Error errror, T image)> DownloadImage(ImageReference uri)
		{
			if (_cache.TryGetValue(uri, out var value))
			{
				return Task.FromResult(value);
			}
			if (_ongoingDownloads.TryGetValue(uri, out var value2))
			{
				return value2;
			}
			Task<(Error, T)> task = DownloadImageInternal(uri);
			if (!task.IsCompleted)
			{
				_ongoingDownloads[uri] = task;
			}
			return task;
		}

		private async Task<(Error, T)> DownloadImageInternal(ImageReference uri)
		{
			var (error, stream) = await ModioClient.Api.DownloadFile(uri.Url);
			if ((bool)error || stream == null)
			{
				T item = await LoadFromDiskCache(uri);
				if (error.Code != ErrorCode.SHUTTING_DOWN)
				{
					ModioLog.Warning?.Log($"Error downloading file at {uri.Url}: {error}");
				}
				_ongoingDownloads.Remove(uri);
				return (Error.None, item);
			}
			MemoryStream memoryStream = new MemoryStream(1048576);
			await stream.CopyToAsync(memoryStream);
			byte[] array = memoryStream.ToArray();
			T item2 = Convert(array);
			_cache[uri] = (Error.None, item2);
			_ongoingDownloads.Remove(uri);
			if (BaseImageCache.PendingDiskSaves.Contains(uri))
			{
				ModioClient.DataStorage.WriteCachedImage(new Uri(uri.Url), array);
				BaseImageCache.PendingDiskSaves.Remove(uri);
			}
			return (Error.None, item2);
		}

		private async Task<T> LoadFromDiskCache(ImageReference imageReference)
		{
			Uri serverPath = new Uri(imageReference.Url);
			var (error, rawBytes) = await ModioClient.DataStorage.ReadCachedImage(serverPath);
			if ((bool)error)
			{
				return null;
			}
			T val = Convert(rawBytes);
			BaseImageCache.PendingDiskSaves.Remove(imageReference);
			_cache[imageReference] = (Error.None, val);
			return val;
		}

		public T GetFirstCachedImage(IEnumerable<ImageReference> imageReferences)
		{
			foreach (ImageReference imageReference in imageReferences)
			{
				T cachedImage = GetCachedImage(imageReference);
				if (cachedImage != null)
				{
					return cachedImage;
				}
			}
			return null;
		}

		protected override bool CacheToDiskInternal(ImageReference imageReference)
		{
			Uri serverPath = new Uri(imageReference.Url);
			T cachedImage = GetCachedImage(imageReference);
			if (cachedImage == null)
			{
				return false;
			}
			byte[] data = ConvertToBytes(cachedImage);
			ModioClient.DataStorage.WriteCachedImage(serverPath, data);
			return true;
		}

		protected abstract T Convert(byte[] rawBytes);

		protected abstract byte[] ConvertToBytes(T image);
	}
	public class ImageCacheBytes : BaseImageCache<byte[]>
	{
		public static readonly ImageCacheBytes Instance = new ImageCacheBytes();

		protected override byte[] Convert(byte[] rawBytes)
		{
			return rawBytes;
		}

		protected override byte[] ConvertToBytes(byte[] image)
		{
			return image;
		}
	}
	[Serializable]
	public struct ImageReference : IEquatable<ImageReference>
	{
		private sealed class UrlEqualityComparer : IEqualityComparer<ImageReference>
		{
			public bool Equals(ImageReference x, ImageReference y)
			{
				return x.Url == y.Url;
			}

			public int GetHashCode(ImageReference obj)
			{
				if (obj.Url == null)
				{
					return 0;
				}
				return obj.Url.GetHashCode();
			}
		}

		public bool IsValid => !string.IsNullOrWhiteSpace(Url);

		public string Url { get; private set; }

		internal ImageReference(string url)
		{
			Url = url;
		}

		public static bool operator ==(ImageReference left, ImageReference right)
		{
			return left.Equals(right);
		}

		public static bool operator !=(ImageReference left, ImageReference right)
		{
			return !left.Equals(right);
		}

		public bool Equals(ImageReference other)
		{
			return Url == other.Url;
		}

		public override bool Equals(object obj)
		{
			if (obj is ImageReference other)
			{
				return Equals(other);
			}
			return false;
		}

		public override int GetHashCode()
		{
			if (Url == null)
			{
				return 0;
			}
			return Url.GetHashCode();
		}
	}
	public class LazyImage<TImage> where TImage : class
	{
		private ImageReference _currentImageReference;

		private BaseImageCache<TImage> _imageCache;

		private bool _failedToLoad;

		public event Action<TImage> OnNewImageAvailable;

		public event Action<bool> OnLoadingActive;

		public LazyImage(BaseImageCache<TImage> imageCache, Action<TImage> onImageAvailable = null, Action<bool> onLoadingActive = null)
		{
			_imageCache = imageCache;
			this.OnNewImageAvailable = onImageAvailable;
			this.OnLoadingActive = onLoadingActive;
		}

		public async void SetImage<T>(ModioImageSource<T> source, T resolution) where T : Enum
		{
			ImageReference uri = source.GetUri(resolution);
			if (uri != _currentImageReference)
			{
				_failedToLoad = false;
			}
			else if (_failedToLoad)
			{
				return;
			}
			_currentImageReference = uri;
			TImage cachedImage = _imageCache.GetCachedImage(_currentImageReference);
			if (cachedImage != null)
			{
				ApplyImage(cachedImage);
				return;
			}
			TImage firstCachedImage = _imageCache.GetFirstCachedImage(source.GetAllReferences());
			if (firstCachedImage != null)
			{
				ApplyImage(firstCachedImage);
			}
			this.OnLoadingActive?.Invoke(obj: true);
			ImageReference currentlyDownloading = _currentImageReference;
			var (error, cachedImage2) = await _imageCache.DownloadImage(_currentImageReference);
			if (_currentImageReference == currentlyDownloading)
			{
				if ((bool)error)
				{
					_failedToLoad = true;
				}
				ApplyImage(cachedImage2);
			}
			this.OnLoadingActive?.Invoke(obj: false);
		}

		private void ApplyImage(TImage cachedImage)
		{
			this.OnNewImageAvailable?.Invoke(cachedImage);
		}
	}
	public class ModioImageSource<TResolution> where TResolution : Enum
	{
		private readonly ImageReference[] _resolutions;

		private bool _isCachingLowestResolution;

		public string FileName { get; private set; }

		internal ModioImageSource(string fileName, params string[] links)
		{
			FileName = fileName;
			_resolutions = new ImageReference[links.Length];
			for (int i = 0; i < _resolutions.Length; i++)
			{
				_resolutions[i] = new ImageReference(links[i]);
			}
		}

		public ImageReference GetUri(TResolution resolution)
		{
			int val = (int)(object)resolution;
			val = Math.Min(_resolutions.Length - 1, val);
			return _resolutions[val];
		}

		public IEnumerable<ImageReference> GetAllReferences()
		{
			return _resolutions;
		}

		public void CacheLowestResolutionOnDisk(bool shouldCache)
		{
			if (_isCachingLowestResolution != shouldCache)
			{
				_isCachingLowestResolution = shouldCache;
				if (_resolutions.Length != 0)
				{
					BaseImageCache.CacheToDisk(_resolutions[0], shouldCache);
				}
			}
		}
	}
