namespace Modio.Customizations
{
	public enum AgreementType
	{
		TermsOfUse = 1,
		PrivacyPolicy,
		GameTerms,
		APIAccessTerms,
		MonetizationTerms,
		AcceptableUsePolicy,
		CookiesPolicy,
		RefundPolicy
	}
	public class Agreement
	{
		internal static Dictionary<AgreementType, Agreement> _agreementCache = new Dictionary<AgreementType, Agreement>();

		public long Id { get; private set; }

		public bool IsActive { get; private set; }

		public bool IsLatest { get; private set; }

		public AgreementType Type { get; private set; }

		public DateTime DateAdded { get; private set; }

		public DateTime DateUpdated { get; private set; }

		public DateTime DateLive { get; private set; }

		public string Name { get; private set; }

		public string Changelog { get; private set; }

		public string Content { get; private set; }

		internal Agreement(AgreementVersionObject agreementObject)
		{
			Id = agreementObject.Id;
			ApplyDetailsFromAgreementObject(agreementObject);
		}

		internal Agreement ApplyDetailsFromAgreementObject(AgreementVersionObject agreementObject)
		{
			Name = agreementObject.Name;
			IsActive = agreementObject.IsActive;
			IsLatest = agreementObject.IsLatest;
			Type = (AgreementType)agreementObject.Type;
			Changelog = agreementObject.Changelog;
			Content = agreementObject.Description;
			DateTimeOffset dateTimeOffset = DateTimeOffset.FromUnixTimeSeconds(agreementObject.DateAdded);
			DateTimeOffset dateTimeOffset2 = DateTimeOffset.FromUnixTimeSeconds(agreementObject.DateUpdated);
			DateTimeOffset dateTimeOffset3 = DateTimeOffset.FromUnixTimeSeconds(agreementObject.DateLive);
			DateAdded = dateTimeOffset.Date;
			DateUpdated = dateTimeOffset2.Date;
			DateLive = dateTimeOffset3.Date;
			return this;
		}

		public static async Task<(Error error, Agreement result)> GetAgreement(AgreementType type, bool forceUpdate = false)
		{
			if (forceUpdate)
			{
				_agreementCache.Remove(type);
			}
			if (_agreementCache.TryGetValue(type, out var value))
			{
				return (error: Error.None, result: value);
			}
			var (error, agreementVersionObject) = await ModioAPI.Agreements.GetCurrentAgreement((long)type);
			if ((bool)error)
			{
				if (!error.IsSilent)
				{
					ModioLog.Error?.Log("Error getting Agreement Type " + type.ToString() + ": " + error.GetMessage());
				}
				return (error: error, result: null);
			}
			Agreement agreement = new Agreement(agreementVersionObject.Value);
			_agreementCache[type] = agreement;
			return (error: error, result: agreement);
		}
	}
	public interface IOculusCredentialProvider
	{
		Task<(Error, string)> GetOculusUserId();

		Task<string> GetOculusAccessToken();

		Task<string> GetOculusUserProof();

		string GetOculusDevice();
	}
	public class ModioOculusAuthService : IModioAuthService, IGetActiveUserIdentifier, IPotentialModioEmailAuthService
	{
		private IOculusCredentialProvider _credentialProvider;

		private bool _isAttemptInProgress;

		public bool IsEmailPlatform => false;

		public ModioAPI.Portal Portal => ModioAPI.Portal.None;

		public Task<string> GetActiveUserIdentifier()
		{
			return Task.FromResult("oculus_user");
		}

		public ModioOculusAuthService(IOculusCredentialProvider credentialProvider)
		{
			_credentialProvider = credentialProvider;
		}

		public ModioOculusAuthService()
		{
		}

		public async Task<Error> Authenticate(bool displayedTerms, string thirdPartyEmail = null)
		{
			if (!_isAttemptInProgress)
			{
				_isAttemptInProgress = true;
				Error error = ValidateAttempt();
				if ((bool)error)
				{
					return ReturnErrorAndReset(error);
				}
				ModioLog.Verbose?.Log("Starting Oculus Authentication, requesting ...");
				var (error2, oculusUserId) = await _credentialProvider.GetOculusUserId();
				if ((bool)error2)
				{
					return ReturnErrorAndReset(error2);
				}
				string oculusAccessToken = await _credentialProvider.GetOculusAccessToken();
				string nonce = await _credentialProvider.GetOculusUserProof();
				string oculusDevice = _credentialProvider.GetOculusDevice();
				var (error3, accessTokenObject) = await ModioAPI.Authentication.AuthenticateViaOculus(new MetaQuestAuthenticationRequest(oculusDevice, nonce, oculusUserId, oculusAccessToken, termsAgreed: true, thirdPartyEmail, 0L));
				if ((bool)error3)
				{
					return ReturnErrorAndReset(error3);
				}
				try
				{
					ModioLog.Verbose?.Log("Oculus authentication successful, authenticating local user...");
					User.Current.OnAuthenticated(accessTokenObject.Value.AccessToken);
				}
				catch (Exception arg)
				{
					ModioLog.Error?.Log("Internal: Failed to deserialize user/token object from Oculus AccessTokenObject and assign to UserData." + $"\n{arg}");
					return new Error(ErrorCode.INTERNAL_FAILED_TO_DESERIALIZE_OBJECT);
				}
				return ReturnErrorAndReset(Error.None);
			}
			return new Error(ErrorCode.USER_AUTHENTICATION_IN_PROGRESS);
		}

		public void SetCredentialProvider(IOculusCredentialProvider credentialProvider)
		{
			_credentialProvider = credentialProvider;
		}

		private Error ValidateAttempt()
		{
			if (_credentialProvider != null)
			{
				return Error.None;
			}
			ModioLog.Error?.Log($"{typeof(ModioSteamAuthService)} cannot authenticate as no Steam Credential Provider" + " has been set! Call ModioSteamAuthService.SetCredentialProvider before calling Authenticate or use a constructor that takes a Credential Provider parameter..");
			return new Error(ErrorCode.NOT_INITIALIZED);
		}

		private Error ReturnErrorAndReset(Error error)
		{
			_isAttemptInProgress = false;
			return error;
		}
	}
	public interface ISteamCredentialProvider
	{
		void RequestEncryptedAppTicket(Action<bool, string> callback);
	}
	public class ModioSteamAuthService : IModioAuthService, IGetActiveUserIdentifier, IPotentialModioEmailAuthService
	{
		private ISteamCredentialProvider _credentialProvider;

		private bool _isAttemptInProgress;

		private string _encryptedAppTicket;

		private Error _encryptedAppTicketError = Error.None;

		public bool IsEmailPlatform => false;

		public ModioAPI.Portal Portal => ModioAPI.Portal.Steam;

		public Task<string> GetActiveUserIdentifier()
		{
			return Task.FromResult("steam_user");
		}

		public ModioSteamAuthService(ISteamCredentialProvider credentialProvider)
		{
			_credentialProvider = credentialProvider;
		}

		public ModioSteamAuthService()
		{
		}

		public async Task<Error> Authenticate(bool displayedTerms, string thirdPartyEmail = null)
		{
			if (!_isAttemptInProgress)
			{
				_isAttemptInProgress = true;
				Error error = ValidateAttempt();
				if ((bool)error)
				{
					return ReturnErrorAndReset(error);
				}
				ModioLog.Verbose?.Log("Starting Steam Authentication, requesting Steam Encrypted App Ticket...");
				_credentialProvider.RequestEncryptedAppTicket(OnGetEncryptedAppTicket);
				while (_encryptedAppTicket == null && _encryptedAppTicketError.Equals(Error.None))
				{
					ModioLog.Verbose?.Log("Waiting for requested Steam Encrypted App Ticket... \n" + $"Ticket: {_encryptedAppTicket} | Error: {_encryptedAppTicketError}");
					await Task.Yield();
				}
				if ((bool)_encryptedAppTicketError)
				{
					return ReturnErrorAndReset(new Error(_encryptedAppTicketError.Code, _encryptedAppTicketError.CustomMessage));
				}
				ModioLog.Verbose?.Log("Received Steam Encrypted App Ticket, requesting Mod.io authentication...");
				var (error2, accessTokenObject) = await ModioAPI.Authentication.AuthenticateViaSteam(new SteamAuthenticationRequest(_encryptedAppTicket, displayedTerms, thirdPartyEmail, 0L));
				if ((bool)error2)
				{
					return ReturnErrorAndReset(error2);
				}
				try
				{
					ModioLog.Verbose?.Log("Steam authentication successful, authenticating local user...");
					User.Current.OnAuthenticated(accessTokenObject.Value.AccessToken);
				}
				catch (Exception arg)
				{
					ModioLog.Error?.Log("Internal: Failed to deserialize user/token object from Steam AccessTokenObject and assign to UserData." + $"\n{arg}");
					return new Error(ErrorCode.INTERNAL_FAILED_TO_DESERIALIZE_OBJECT);
				}
				return ReturnErrorAndReset(Error.None);
			}
			return new Error(ErrorCode.USER_AUTHENTICATION_IN_PROGRESS);
		}

		private void OnGetEncryptedAppTicket(bool success, string encryptedAppTicketOrError)
		{
			ModioLog.Verbose?.Log($"Got Steam Encrypted App Ticket: {success} | Ticket: {encryptedAppTicketOrError} | " + $"attemptInProgress: {_isAttemptInProgress} | ");
			if (_isAttemptInProgress)
			{
				if (!success)
				{
					ModioLog.Error?.Log(encryptedAppTicketOrError);
					_encryptedAppTicketError = new Error(ErrorCode.STEAM_FAILED_TO_GET_APP_TICKET, encryptedAppTicketOrError);
				}
				else
				{
					_encryptedAppTicket = encryptedAppTicketOrError;
				}
			}
		}

		public void SetCredentialProvider(ISteamCredentialProvider credentialProvider)
		{
			_credentialProvider = credentialProvider;
		}

		private Error ValidateAttempt()
		{
			if (_credentialProvider != null)
			{
				return Error.None;
			}
			ModioLog.Error?.Log($"{typeof(ModioSteamAuthService)} cannot authenticate as no Steam Credential Provider" + " has been set! Call ModioSteamAuthService.SetCredentialProvider before calling Authenticate or use a constructor that takes a Credential Provider parameter..");
			return new Error(ErrorCode.NOT_INITIALIZED);
		}

		private Error ReturnErrorAndReset(Error error)
		{
			_encryptedAppTicketError = Error.None;
			_encryptedAppTicket = null;
			_isAttemptInProgress = false;
			return error;
		}
	}
	public struct ExternalAuthenticationToken
	{
		public string url;

		public string autoUrl;

		public string code;

		public Task<(Error, WssLoginSuccess)> task;

		public DateTime expiryTime;

		internal Action cancel { get; set; }

		public void Cancel()
		{
			cancel?.Invoke();
			cancel = null;
		}
	}
	public class ModioWssAuthService : IModioAuthService, IGetActiveUserIdentifier, IPotentialModioEmailAuthService
	{
		private IWssAuthPrompter _authPrompter;

		private bool _isAttemptInProgress;

		private ExternalAuthenticationToken _authToken;

		public bool IsEmailPlatform => false;

		public ModioAPI.Portal Portal => ModioAPI.Portal.None;

		public Task<string> GetActiveUserIdentifier()
		{
			return Task.FromResult("linked_account_user");
		}

		public ModioWssAuthService(IWssAuthPrompter prompter)
		{
			_authPrompter = prompter;
		}

		public ModioWssAuthService()
		{
		}

		public async Task<Error> Authenticate(bool displayedTerms, string thirdPartyEmail = null)
		{
			if (!_isAttemptInProgress)
			{
				_isAttemptInProgress = true;
				Error error = ValidateAttempt();
				if ((bool)error)
				{
					return ReturnErrorAndReset(error);
				}
				var (error2, authToken) = await Wss.BeginAuthenticationProcess();
				if ((bool)error2)
				{
					return ReturnErrorAndReset(error2);
				}
				_authToken = authToken;
				_authPrompter.ShowPrompt(authToken.url, authToken.code);
				var (error3, wssLoginSuccess) = await authToken.task;
				if ((bool)error3)
				{
					return ReturnErrorAndReset(error3);
				}
				_authToken = default(ExternalAuthenticationToken);
				try
				{
					User.Current.OnAuthenticated(wssLoginSuccess.access_token);
					ModioLog.Verbose?.Log("Wss authentication successful, authenticating local user...");
				}
				catch (Exception arg)
				{
					ModioLog.Error?.Log("Internal: Failed to deserialize user/token object from WssMessage and assign to UserData." + $"\n{arg}");
					return ReturnErrorAndReset(new Error(ErrorCode.INTERNAL_FAILED_TO_DESERIALIZE_OBJECT));
				}
				return ReturnErrorAndReset(Error.None);
			}
			return new Error(ErrorCode.USER_AUTHENTICATION_IN_PROGRESS);
		}

		private Error ValidateAttempt()
		{
			if (_authPrompter != null)
			{
				return Error.None;
			}
			ModioLog.Error?.Log($"{typeof(ModioWssAuthService)} cannot authenticate as no Prompter has been set! " + "Call ModioWssAuthService.SetPrompter before calling Authenticate or use a constructor that takes a Prompter parameter..");
			return new Error(ErrorCode.NOT_INITIALIZED);
		}

		private Error ReturnErrorAndReset(Error error)
		{
			_isAttemptInProgress = false;
			return error;
		}

		public void SetPrompter(IWssAuthPrompter prompter)
		{
			_authPrompter = prompter;
		}

		public bool InProgress()
		{
			return _isAttemptInProgress;
		}

		public void Cancel()
		{
			if (_isAttemptInProgress && _authToken.task != null)
			{
				_authToken.Cancel();
			}
		}
	}
	internal static class Wss
	{
		public static async Task<(Error, ExternalAuthenticationToken)> BeginAuthenticationProcess(bool restartProcess = false)
		{
			(Error, WssDeviceLoginResponse) tuple = await WssHandler.DoMessageHandshake<WssDeviceLoginResponse>(WssRequest.DeviceLogin());
			if ((bool)tuple.Item1)
			{
				return (tuple.Item1, default(ExternalAuthenticationToken));
			}
			Task<(Error, WssLoginSuccess)> task = WaitForAccessToken();
			ExternalAuthenticationToken item = new ExternalAuthenticationToken
			{
				code = tuple.Item2.code,
				url = tuple.Item2.login_url,
				autoUrl = tuple.Item2.login_url + "?code=" + tuple.Item2.code,
				expiryTime = DateTimeOffset.FromUnixTimeSeconds(tuple.Item2.date_expires).DateTime,
				task = task,
				cancel = delegate
				{
					WssHandler.CancelWaitingFor("login_success");
				}
			};
			return (Error.None, item);
		}

		private static async Task<(Error, WssLoginSuccess)> WaitForAccessToken()
		{
			(Error, WssMessage) tuple = await WssHandler.WaitForMessage("login_success");
			WssLoginSuccess output = new WssLoginSuccess
			{
				access_token = "",
				code = -1L,
				date_expires = -1L
			};
			var (error, _) = tuple;
			if (!error)
			{
				error = ((!tuple.Item2.TryGetValue<WssLoginSuccess>(out output)) ? new Error(ErrorCode.WSS_UNEXPECTED_MESSAGE) : Error.None);
			}
			WssHandler.Shutdown();
			return (error, output);
		}
	}
	internal static class WssHandler
	{
		private static ISocketConnection Socket = new SocketConnection();

		private static Dictionary<string, TaskCompletionSource<WssMessage>> WaitingForMessages = new Dictionary<string, TaskCompletionSource<WssMessage>>();

		private static Dictionary<string, Action<WssMessage>> SubscribedMessageListeners = new Dictionary<string, Action<WssMessage>>();

		private static Dictionary<string, WssMessage> UnhandledMessages = new Dictionary<string, WssMessage>();

		private static string GatewayUrl => string.Format("wss://g-{0}.ws.{1}.io/", ModioClient.Settings.GameId, Regex.Match(ModioClient.Settings.ServerURL, "https://[^.]+.(?<domain>.+).io").Groups["domain"]);

		public static async Task<(Error, WssMessage)> WaitForMessage(string messageOperation, bool checkPreviousUnhandledMessages = false)
		{
			if (checkPreviousUnhandledMessages && UnhandledMessages.ContainsKey(messageOperation))
			{
				(Error, WssMessage) result = (Error.None, UnhandledMessages[messageOperation]);
				UnhandledMessages.Remove(messageOperation);
				return result;
			}
			TaskCompletionSource<WssMessage> tcs = new TaskCompletionSource<WssMessage>();
			while (WaitingForMessages.ContainsKey(messageOperation))
			{
				await WaitingForMessages[messageOperation].Task;
			}
			WaitingForMessages.Add(messageOperation, tcs);
			await Task.WhenAny(tcs.Task, Task.Delay(900000));
			Error error = (tcs.Task.IsCompleted ? Error.None : new Error(ErrorCode.WSS_MESSAGE_TIMEOUT));
			WssMessage item = (tcs.Task.IsCompleted ? tcs.Task.Result : default(WssMessage));
			if (!error && string.IsNullOrEmpty(item.operation))
			{
				error = new Error(ErrorCode.OPERATION_CANCELLED);
			}
			return (error, item);
		}

		public static async Task<(Error, T)> DoMessageHandshake<T>(WssMessage message) where T : struct
		{
			Task<(Error, WssMessage)> task = WaitForMessage("device_login");
			Error error = await Send(message);
			ModioLog.Verbose?.Log("[Socket] SENT (" + message.operation + ")");
			if ((bool)error)
			{
				ModioLog.Verbose?.Log("[Socket] Failed to send");
				return (error, default(T));
			}
			ModioLog.Verbose?.Log("[Socket] Waiting for initial response");
			(Error, WssMessage) tuple = await task;
			if (!tuple.Item1)
			{
				ModioLog.Verbose?.Log("[Socket] deserializing initial response");
				if (tuple.Item2.TryGetValue<T>(out var output))
				{
					return (Error.None, output);
				}
				ModioLog.Verbose?.Log("[Socket] Failed to deserialize");
				return (new Error(ErrorCode.WSS_UNEXPECTED_MESSAGE), default(T));
			}
			return (tuple.Item1, default(T));
		}

		public static void CancelWaitingFor(string messageOperation)
		{
			if (WaitingForMessages.ContainsKey(messageOperation))
			{
				TaskCompletionSource<WssMessage> taskCompletionSource = WaitingForMessages[messageOperation];
				WaitingForMessages.Remove(messageOperation);
				taskCompletionSource.SetResult(default(WssMessage));
			}
		}

		private static void CancelAllAwaitingMessages()
		{
			List<TaskCompletionSource<WssMessage>> list = WaitingForMessages.Values.ToList();
			WaitingForMessages.Clear();
			foreach (TaskCompletionSource<WssMessage> item in list)
			{
				item.SetResult(default(WssMessage));
			}
		}

		public static async Task Shutdown()
		{
			await Socket.CloseConnection();
			CancelAllAwaitingMessages();
			UnhandledMessages.Clear();
			await Task.Yield();
		}

		private static async Task<Error> EnsureConnection()
		{
			if (!Socket.Connected())
			{
				return await Socket.SetupConnection(GatewayUrl, Receive, Disconnected);
			}
			return Error.None;
		}

		public static async Task<Error> Send(WssMessage message)
		{
			WssMessages messages = new WssMessages(message);
			Error error = await EnsureConnection();
			if ((bool)error)
			{
				return error;
			}
			return await Socket.SendData(messages);
		}

		private static void Receive(WssMessages messages)
		{
			WssMessage[] messages2 = messages.messages;
			for (int i = 0; i < messages2.Length; i++)
			{
				WssMessage wssMessage = messages2[i];
				if (wssMessage.operation == "failed_operation")
				{
					ProcessErrorObject(wssMessage);
					continue;
				}
				if (WaitingForMessages.ContainsKey(wssMessage.operation))
				{
					TaskCompletionSource<WssMessage> taskCompletionSource = WaitingForMessages[wssMessage.operation];
					WaitingForMessages.Remove(wssMessage.operation);
					taskCompletionSource.SetResult(wssMessage);
					continue;
				}
				ModioLog.Verbose?.Log("[Socket] Received unexpected message operation (" + wssMessage.operation + ").\nCaching it temporarily in case we listen for it immediately after.");
				if (UnhandledMessages.ContainsKey(wssMessage.operation))
				{
					UnhandledMessages[wssMessage.operation] = wssMessage;
				}
				else
				{
					UnhandledMessages.Add(wssMessage.operation, wssMessage);
				}
			}
		}

		private static void ProcessErrorObject(WssMessage message)
		{
			if (message.TryGetValue<WssErrorObject>(out var output))
			{
				ModioLog.Error?.Log("[Socket] Error received from WssMessages:\n" + $"Error: [{output.error.code}]" + $" [{output.error.error_ref}]" + " " + output.error.message);
				if (WaitingForMessages.ContainsKey(output.operation))
				{
					TaskCompletionSource<WssMessage> taskCompletionSource = WaitingForMessages[output.operation];
					WaitingForMessages.Remove(output.operation);
					taskCompletionSource.SetResult(default(WssMessage));
				}
				else if (SubscribedMessageListeners.ContainsKey(output.operation))
				{
					SubscribedMessageListeners[output.operation]?.Invoke(message);
					WaitingForMessages.Remove(output.operation);
				}
				else
				{
					ModioLog.Warning?.Log("[Socket:Internal] Could not find any matching listener for the error operation: " + output.operation);
				}
			}
			else
			{
				ModioLog.Error?.Log("[Socket:Internal] Failed to cast WssMessage (operation \"" + message.operation + "\") into WssErrorObject");
			}
		}

		private static async void Disconnected()
		{
			if (WaitingForMessages.Count > 0)
			{
				ModioLog.Warning?.Log("[Socket] Disconnected while the WssHandler was still waiting for messages. Attempting to reconnect the WebSocket.");
				CancelAllAwaitingMessages();
				if ((bool)(await EnsureConnection()))
				{
					ModioLog.Error?.Log("[Socket] Failed to re-establish Socket connection. Listeners for WssMessages have been cancelled");
				}
				else
				{
					ModioLog.Warning?.Log("[Socket] Re-established Socket connection. Listeners for WssMessages have been cancelled");
				}
			}
		}
	}
