	public struct ModioAPIFileParameter
	{
		public bool Unused;

		public string Name;

		public readonly string ContentType;

		public readonly string MediaType;

		public string Path;

		private readonly Stream _stream;

		public static ModioAPIFileParameter None => new ModioAPIFileParameter
		{
			Unused = true
		};

		public ModioAPIFileParameter(string name, string contentType, string path)
		{
			Name = name;
			ContentType = contentType;
			MediaType = "multipart/form-data";
			Path = path;
			Unused = false;
			_stream = null;
		}

		public ModioAPIFileParameter(Stream stream)
		{
			this = default(ModioAPIFileParameter);
			_stream = stream;
		}

		public ModioAPIFileParameter(Stream stream, string name, string contentType)
		{
			this = default(ModioAPIFileParameter);
			_stream = stream;
			ContentType = contentType;
			Name = name;
		}

		public Stream GetContent()
		{
			object obj = _stream;
			if (obj == null)
			{
				if (Path != null)
				{
					return new FileStream(Path, FileMode.Open, FileAccess.Read, FileShare.ReadWrite);
				}
				obj = null;
			}
			return (Stream)obj;
		}
	}
	public class ModioAPIRequest : IDisposable
	{
		private static readonly List<ModioAPIRequest> Pool = new List<ModioAPIRequest>();

		private string Uri { get; set; }

		public ModioAPIRequestOptions Options { get; } = new ModioAPIRequestOptions();

		public ModioAPIRequestMethod Method { get; private set; }

		public ModioAPIRequestContentType ContentType { get; private set; }

		public string ContentTypeHint { get; private set; } = "";

		private ModioAPIRequest()
		{
		}

		internal static ModioAPIRequest New(string uri, ModioAPIRequestMethod method = ModioAPIRequestMethod.Get, ModioAPIRequestContentType contentType = ModioAPIRequestContentType.None, string contentTypeHint = "")
		{
			ModioAPIRequest modioAPIRequest;
			lock (Pool)
			{
				if (Pool.Count == 0)
				{
					modioAPIRequest = new ModioAPIRequest();
				}
				else
				{
					int index = Pool.Count - 1;
					modioAPIRequest = Pool[index];
					Pool.RemoveAt(index);
				}
			}
			modioAPIRequest.Uri = uri;
			modioAPIRequest.Method = method;
			modioAPIRequest.ContentType = contentType;
			modioAPIRequest.ContentTypeHint = contentTypeHint;
			return modioAPIRequest;
		}

		public string GetUri(List<string> defaultParameters)
		{
			string[] array = new string[defaultParameters.Count + Options.QueryParameters.Count];
			if (array.Length == 0)
			{
				return Uri;
			}
			Options.QueryParameters.Select((KeyValuePair<string, string> key) => key.Key + "=" + key.Value).ToArray().CopyTo(array, 0);
			defaultParameters.CopyTo(array, Options.QueryParameters.Count);
			if (array.Length != 0)
			{
				return Uri + ((Uri.LastIndexOf('?') == -1) ? "?" : "&") + string.Join("&", array);
			}
			return Uri;
		}

		public void Dispose()
		{
			Options.Dispose();
			Method = ModioAPIRequestMethod.Get;
			ContentType = ModioAPIRequestContentType.None;
			lock (Pool)
			{
				Pool.Add(this);
			}
		}
	}
	public enum ModioAPIRequestContentType
	{
		None,
		Multipart,
		Stream,
		String,
		FormUrlEncoded,
		ByteArray,
		MultipartFormData
	}
	public enum ModioAPIRequestMethod
	{
		Get,
		Delete,
		Post,
		Put,
		Head,
		Options,
		Trace
	}
	public class ModioAPIRequestOptions : IDisposable
	{
		internal Dictionary<string, string> QueryParameters { get; } = new Dictionary<string, string>();

		internal Dictionary<string, string> HeaderParameters { get; } = new Dictionary<string, string>();

		internal bool RequiresAuthentication { get; private set; }

		internal Dictionary<string, string> FormParameters { get; } = new Dictionary<string, string>();

		internal Dictionary<string, ModioAPIFileParameter> FileParameters { get; } = new Dictionary<string, ModioAPIFileParameter>();

		public byte[] BodyDataBytes { get; private set; }

		public void Dispose()
		{
			RequiresAuthentication = false;
			HeaderParameters.Clear();
			QueryParameters.Clear();
			FormParameters.Clear();
			FileParameters.Clear();
		}

		internal void AddQueryParameter(string key, object value)
		{
			if (value != null)
			{
				QueryParameters.Add(key, ParameterToString(value));
			}
		}

		internal void AddHeaderParameter(string key, object value)
		{
			if (value != null)
			{
				HeaderParameters.Add(key, ParameterToString(value));
			}
		}

		internal void AddFilterParameters(SearchFilter filter)
		{
			if (filter == null)
			{
				return;
			}
			AddQueryParameter("_offset", filter.PageIndex * filter.PageSize);
			AddQueryParameter("_limit", filter.PageSize);
			foreach (KeyValuePair<string, object> parameter in filter.Parameters)
			{
				AddQueryParameter(parameter.Key, parameter.Value);
			}
		}

		public void RequireAuthentication()
		{
			RequiresAuthentication = true;
		}

		private static string ParameterToString(object value)
		{
			if (value == null)
			{
				return string.Empty;
			}
			if (value is IEnumerable<string> values)
			{
				return string.Join(",", values);
			}
			if (value is ICollection collection)
			{
				StringBuilder stringBuilder = new StringBuilder();
				int num = 0;
				foreach (object item in collection)
				{
					if (num++ > 0)
					{
						stringBuilder.Append(",");
					}
					stringBuilder.Append(item);
				}
				return stringBuilder.ToString();
			}
			return $"{value}";
		}

		public void AddBody(byte[] data)
		{
			BodyDataBytes = data;
		}

		public void AddBody(IApiRequest request)
		{
			foreach (KeyValuePair<string, object> bodyParameter in request.GetBodyParameters())
			{
				if (bodyParameter.Value is ModioAPIFileParameter value)
				{
					FileParameters.Add(bodyParameter.Key, value);
				}
				else if (bodyParameter.Value != null)
				{
					FormParameters.Add(bodyParameter.Key, ParameterToString(bodyParameter.Value));
				}
			}
		}

		public void AddBody(IApiRequest request, string hint)
		{
			if (hint == "application/json")
			{
				string s = JsonConvert.SerializeObject(from param in request.GetBodyParameters()
					where param.Value != null
					select param);
				AddBody(Encoding.UTF8.GetBytes(s));
			}
			else
			{
				AddBody(request);
			}
		}
	}
	public class ModioAPITestSettings : IModioServiceSettings
	{
		public bool FakeDisconnected;

		public string FakeDisconnectedOnEndpointRegex;

		public float FakeDisconnectedTimeoutDuration;

		public bool RateLimitError;

		public string RateLimitOnEndpointRegex;

		public bool ShouldFakeDisconnected(string url)
		{
			if (FakeDisconnected)
			{
				return true;
			}
			if (!string.IsNullOrEmpty(FakeDisconnectedOnEndpointRegex))
			{
				return Regex.IsMatch(url, FakeDisconnectedOnEndpointRegex);
			}
			return false;
		}

		public bool ShouldFakeRateLimit(string url)
		{
			if (RateLimitError)
			{
				return true;
			}
			if (!string.IsNullOrEmpty(RateLimitOnEndpointRegex))
			{
				return Regex.IsMatch(url, RateLimitOnEndpointRegex);
			}
			return false;
		}
	}
